// ============================================================
// SCENARIO GENERATOR - this is the heart of the chaos engine.
// Edit WEIGHTS here to change how often each scenario appears.
// tier 0 = healthy, 1 = benign anomaly, 2 = common failure,
// tier 3 = rare/complex, 4 = rare-of-the-rare.
// ============================================================
const CATALOG = [
  {
    "id": "happy_path",
    "tier": 0,
    "weight": 0.45,
