  },
  {
    "id": "dependency_deadlock",
    "tier": 4,
    "weight": 0.002,
    "duration_s": 300
  }
];

const HEALTHY = CATALOG.filter(s => s.tier <= 1);

function weightedPick(pool) {
  const total = pool.reduce((a, s) => a + s.weight, 0);
  let r = Math.random() * total;
  for (const s of pool) { r -= s.weight; if (r <= 0) return s; }
  return pool[pool.length - 1];
}

const sd = $getWorkflowStaticData('global');
const now = Date.now();

// Expire a finished incident
if (sd.activeIncident && now > sd.activeIncident.until) {
  sd.lastIncident = { ...sd.activeIncident, ended_at: new Date().toISOString() };
  sd.activeIncident = null;
}
const incident = sd.activeIncident || null;

// Burst size: realistic jitter so traffic is never perfectly flat
const burst = 3 + Math.floor(Math.random() * 6);
const out = [];

for (let i = 0; i < burst; i++) {
  let chosen;
  let injected = false;

  if (incident && Math.random() < (incident.blast_radius ?? 0.6)) {
    chosen = CATALOG.find(s => s.id === incident.scenario_id) || CATALOG[0];
    injected = true;
  } else {
    chosen = incident ? weightedPick(HEALTHY) : weightedPick(CATALOG);
  }

  out.push({
    json: {
      request_id: 'req_' + Math.random().toString(36).slice(2, 12),
      session_id: 'sess_' + Math.random().toString(36).slice(2, 8),
      user_id: 'user_' + (1 + Math.floor(Math.random() * 40)),
      scenario_id: chosen.id,
      tier: chosen.tier,
      injected,
      incident_id: incident ? incident.incident_id : null,
      emitted_at: new Date().toISOString()
    }
  });
}

return out;

// ============================================================
// CHAOS CONTROLLER
// POST /webhook/chaos  { "scenario_id": "db_pool_exhausted",
//                       "duration_s": 300, "blast_radius": 0.6 }
// POST /webhook/chaos  { "action": "clear" }
// POST /webhook/chaos  { "action": "status" }
// Holds a SUSTAINED incident so SigNoz alert thresholds actually breach.
// ============================================================
const body = $input.first().json.body || $input.first().json || {};
const sd = $getWorkflowStaticData('global');
const now = Date.now();

if (sd.activeIncident && now > sd.activeIncident.until) sd.activeIncident = null;

if (body.action === 'clear') {
  const was = sd.activeIncident;
  sd.activeIncident = null;
  return [{ json: { ok: true, cleared: true, was } }];
}

if (body.action === 'status') {
  return [{ json: { ok: true, active: sd.activeIncident || null, last: sd.lastIncident || null } }];
}

if (!body.scenario_id) {
  return [{ json: { ok: false, error: 'scenario_id required (or action: clear|status)' } }];
}

const duration_s = Number(body.duration_s) || 300;
sd.activeIncident = {
  incident_id: 'inc_' + Math.random().toString(36).slice(2, 10),
  scenario_id: body.scenario_id,
  blast_radius: body.blast_radius != null ? Number(body.blast_radius) : 0.6,
  started_at: new Date().toISOString(),
  until: now + duration_s * 1000
};

return [{ json: { ok: true, incident: sd.activeIncident } }];
